import { Box, Tooltip, withStyles } from "@material-ui/core"
import React from "react"
import AspectRatioIcon from "@material-ui/icons/AspectRatio"
import HeightIcon from "@material-ui/icons/Height"
import SettingsOverscanIcon from "@material-ui/icons/SettingsOverscan"
import FourKIcon from "@material-ui/icons/FourK"
import HdIcon from "@material-ui/icons/Hd"

const ScreenTooltipBase = withStyles(theme => {
  return {
    tooltip: {
      background: "#68c",
    },
  }
})(Tooltip)

const ScreenTooltip = ({ title, Icon }) => {
  return (
    <ScreenTooltipBase title={title}>
      <Icon style={{ margin: "0.3rem 0.5rem" }} />
    </ScreenTooltipBase>
  )
}

export default function () {
  return (
    <Box
      display="inline-flex"
      mx="auto"
      justifyContent="center"
      flexWrap="wrap"
    >
      <ScreenTooltip title="Aspect Ratio" Icon={AspectRatioIcon} />
      <ScreenTooltip title="Scalable Distance" Icon={HeightIcon} />
      <ScreenTooltip title="Field of View (FOV)" Icon={SettingsOverscanIcon} />
      <ScreenTooltip title="Retina Detected" Icon={FourKIcon} />
      <ScreenTooltip title="Preset Size" Icon={HdIcon} />
    </Box>
  )
}
