import {
  Button,
  Card,
  Checkbox,
  Divider,
  FormControl,
  IconButton,
  Input,
  InputAdornment,
  InputLabel,
  makeStyles,
  Snackbar,
  TextField,
  Typography,
} from "@material-ui/core"
import CloseIcon from "@material-ui/icons/Close"

import React, { useState } from "react"
import { useSelector, useDispatch } from "react-redux"
import {
  setWidth,
  setHeight,
  selectWidth,
  selectHeight,
  setSize,
  saveDevice,
  setName,
  setCurvature,
  setUseCurvature,
  setAspect,
} from "../../state/displaySlice"

const useStyles = makeStyles(theme => {
  return {
    screenCard: {
      // display: 'flexbl',
      // height: '100%',
      borderRadius: 0,
      border: "none",
      boxShadow: "0 0 2rem #3333",
      padding: theme.spacing(2),
      // margin: theme.spacing(1),
      textAlign: "center",
      "&>*": {
        margin: "0.5rem 0",
      },
      position: "sticky",
      top: 0,
    },
  }
})

const Saved = ({ open, close, name }) => {
  return (
    <Snackbar
      anchorOrigin={{
        vertical: "bottom",
        horizontal: "left",
      }}
      open={open}
      autoHideDuration={2000}
      onClose={close}
      message={`Device Saved | ${name}`}
      action={
        <>
          <IconButton
            size="small"
            aria-label="close"
            color="inherit"
            onClick={close}
          >
            <CloseIcon fontSize="small" />
          </IconButton>
        </>
      }
    />
  )
}

export default () => {
  const classes = useStyles()
  const width = useSelector(selectWidth)
  const height = useSelector(selectHeight)
  const size = useSelector(state => state?.display?.size)
  const asp = useSelector(state => state?.display?.aspect)
  const name = useSelector(state => state?.display?.name)
  const curvature = useSelector(state => state?.display?.curvature.r)
  const dispatch = useDispatch()
  const useCurvature = useSelector(state => state?.display?.curvature.use)

  const [openSnackbar, setOpenSnackbar] = useState(false)

  const toOpenSnackbar = () => {
    setOpenSnackbar(true)
  }
  const toCloseSnackbar = () => {
    setOpenSnackbar(false)
  }
  const handleFocus = e => e?.target?.select && e.target.select()

  return (
    <Card className={classes.screenCard} variant="outlined">
      <TextField
        fullWidth
        id="device-name"
        label="name"
        name="name"
        type="text"
        value={name}
        onClick={handleFocus}
        onChange={e => {
          if (e.target.value !== undefined) {
            dispatch(setName(e.target.value))
          }
        }}
      />
      <Typography variant="caption">Resolution</Typography>
      <TextField
        fullWidth
        id="screen-width"
        label="Width resolution"
        name="Width resolution"
        type="number"
        value={width}
        onClick={handleFocus}
        onChange={e => {
          if (e.target.value !== undefined) {
            dispatch(setWidth(e.target.value))
          }
        }}
      />
      <TextField
        fullWidth
        id="screen-height"
        label="Height resolution"
        name="Height resolution"
        type="number"
        value={height}
        onClick={handleFocus}
        onChange={e => dispatch(setHeight(e.target.value))}
      />
      <Typography variant="caption">Aspect Ratio</Typography>
      <TextField
        fullWidth
        id="asp-width"
        label="aspect width"
        type="number"
        // helperText='Height resolution'
        value={asp.w || undefined}
        onClick={handleFocus}
        onChange={e =>
          dispatch(setAspect({ type: "w", ratio: Number(e.target.value) }))
        }
      />
      <TextField
        fullWidth
        id="asp-height"
        label="aspect height"
        type="number"
        // helperText='Height resolution'
        value={asp.h}
        onClick={handleFocus}
        onChange={e =>
          dispatch(setAspect({ type: "h", ratio: Number(e.target.value) }))
        }
      />
      <Typography variant="caption">Screen Size</Typography>
      <FormControl fullWidth>
        <InputLabel htmlFor="screen-size">Diagonal Size</InputLabel>
        <Input
          id="screen-size"
          type="number"
          value={size}
          onClick={handleFocus}
          onChange={e => dispatch(setSize(e.target.value))}
          endAdornment={
            <InputAdornment position="end">inch(es)</InputAdornment>
          }
        />
      </FormControl>

      <FormControl fullWidth>
        <InputLabel htmlFor="Curvature">Curvature (R)</InputLabel>
        <Input
          disabled={!useCurvature}
          id="Curvature"
          type="number"
          value={curvature}
          onClick={handleFocus}
          onChange={e => dispatch(setCurvature(e.target.value))}
          startAdornment={
            <InputAdornment position="start">
              <Checkbox
                checked={useCurvature}
                onChange={e => {
                  dispatch(setUseCurvature(!useCurvature))
                }}
                inputProps={{ "aria-label": "primary checkbox" }}
              />
            </InputAdornment>
          }
          endAdornment={<InputAdornment position="end">mm</InputAdornment>}
        />
      </FormControl>
      <Divider />
      <Button
        onClick={e => {
          dispatch(saveDevice())
          toOpenSnackbar()
        }}
        variant="outlined"
      >
        Save
      </Button>
      <Saved name={name} open={openSnackbar} close={toCloseSnackbar} />
    </Card>
  )
}
