import React, { useEffect, useState } from "react"
import { useSelector, useDispatch } from "react-redux"

import { loadFullState } from "../../state/displaySlice"

const StorageHandler = ({ display }) => {
  const key = "screen-redux"
  const dispatch = useDispatch()
  const [init, setInit] = useState(false)
  useEffect(() => {
    const data = localStorage.getItem(key)
    if (data) {
      const screen_data = JSON.parse(data)
      dispatch(loadFullState(screen_data))
    }
    setInit(true)
  }, [dispatch])
  useEffect(() => {
    if (init) {
      localStorage.setItem(key, JSON.stringify(display))
    }
  }, [display, init])
  return <></>
}

export default () => {
  const display = useSelector(state => state.display)
  return <StorageHandler display={display} />
}
