import { Box, Container, CssBaseline, Grid } from "@material-ui/core"
import React from "react"

import SEO from "../components/seo"
import ScreenUseCases from "../components/screen/screen-usecases"
import ScreenCard from "../components/screen/screen_spec"
import ScreenList from "../components/screen/screenList"
import ScreenBlock from "../components/screen/screen-block"
import SocialMedia from "../components/social-media"
import "fontsource-roboto"
import screenCss from "!raw-loader!sass-loader!../css/screen.css"
import data from "../datasheet/screen_site.yml"

import StorageHandler from "../components/screen/screen-storage"

import { Helmet } from "react-helmet"

export default () => {
  return (
    <>
      <Helmet>
        <style>{screenCss}</style>
        <style>{"html{background-color: #333}"}</style>
      </Helmet>
      <SEO {...data.SEO} />
      <CssBaseline />
      <StorageHandler /> {/** for localStorage Redux Store **/}
      <Container maxWidth={false} disableGutters className="screen-head">
        <h1 children={data.Header.title} />
        <ScreenUseCases />
        <p role="doc-subtitle" children={data.Header.description} />
      </Container>
      <Container maxWidth="xl" disableGutters>
        <Grid container>
          <Grid item xs={12} md={3} lg={2}>
            <ScreenList />
          </Grid>
          <Grid item xs={12} md={6} lg={8}>
            <ScreenBlock />
          </Grid>
          <Grid item xs={12} md={3} lg={2}>
            <ScreenCard />
          </Grid>
        </Grid>
      </Container>
      <Box role="contentinfo" bgcolor="#333" py={4}>
        <SocialMedia />
      </Box>
    </>
  )
}
